/**
 * Account Page JavaScript
 * This script handles the functionality for the user account page
 */
import './accountpage.css'; // Import CSS for the account page
import { initHeader } from './header.js'; // Import header initialization
import { initFooter } from './footer.js'; // Import footer initialization
import { initAddressManager } from './manageaddress.js'; // Import address manager

document.addEventListener('DOMContentLoaded', function () {
  // Initialize the account page
  initAccountPage();
});

/**
 * Initialize all account page functionality
 */
function initAccountPage() {
  // Add event listeners to boxes for interaction
  initBoxInteractions();

  // Load user data if available
  loadUserData();

  // Initialize any notifications or alerts
  checkNotifications();
}

/**
 * Add interaction behaviors to the account boxes
 */
function initBoxInteractions() {
  const boxes = document.querySelectorAll('.box');
  boxes.forEach(box => {
    // Add hover effect
    box.addEventListener('mouseenter', function () {
      this.classList.add('box-hover');
    });
    box.addEventListener('mouseleave', function () {
      this.classList.remove('box-hover');
    });

    // Add click effect (optional - for mobile)
    box.addEventListener('click', function (e) {
      // Only trigger if the box itself was clicked, not a link inside it
      if (e.target === this || e.target.classList.contains('box-content') || e.target.classList.contains('box-icon')) {
        // Find the first link in this box and navigate to it
        const firstLink = this.querySelector('a');
        if (firstLink) {
          window.location.href = firstLink.getAttribute('href');
        }
      }
    });
  });
}

/**
 * Load user data from storage or API
 */
function loadUserData() {
  // Example: Load user data from localStorage or an API
  const userData = localStorage.getItem('userData');
  if (userData) {
    const user = JSON.parse(userData);
    updateUserInterface(user);
  } else {
    // If no stored data, you might want to fetch from an API
    fetchUserData();
  }
}

/**
 * Fetch user data from an API endpoint
 */
function fetchUserData() {
  // This is a placeholder for an actual API call
  // In a real application, you would make a fetch or XMLHttpRequest here

  // Example:
  /*
  fetch('/api/user-data')
      .then(response => response.json())
      .then(user => {
          // Store the user data
          localStorage.setItem('userData', JSON.stringify(user));

          // Update the UI with user data
          updateUserInterface(user);
      })
      .catch(error => {
          console.error('Error fetching user data:', error);
      });
  */

  // For demonstration, we'll use placeholder data
  const placeholderUser = {
    name: "John Doe",
    email: "john.doe@example.com",
    profileImage: "/src/pics/profile-account-picture.png",
    orderCount: 5,
    hasNotifications: true
  };

  // Save to localStorage for future use
  localStorage.setItem('userData', JSON.stringify(placeholderUser));

  // Update UI
  updateUserInterface(placeholderUser);
}

/**
 * Update the user interface with user data
 * @param {Object} user - The user data object
 */
function updateUserInterface(user) {
  // Update user name in the header
  const userNameElement = document.querySelector('.user-name');
  if (userNameElement && user.name) {
    userNameElement.textContent = user.name;
  }

  // Update profile image if needed
  const profileImageElement = document.querySelector('.profile-image img');
  if (profileImageElement && user.profileImage) {
    profileImageElement.src = user.profileImage;
    profileImageElement.alt = `${user.name}'s Profile Picture`;
  }

  // Update order count if available
  if (user.orderCount) {
    const ordersBox = document.querySelector('.box h3:contains("Your Orders")');
    if (ordersBox) {
      const orderCountSpan = document.createElement('span');
      orderCountSpan.className = 'count-badge';
      orderCountSpan.textContent = user.orderCount;
      ordersBox.appendChild(orderCountSpan);
    }
  }
}

/**
 * Check for any notifications or alerts to display
 */
function checkNotifications() {
  const userData = localStorage.getItem('userData');
  if (userData) {
    const user = JSON.parse(userData);
    if (user.hasNotifications) {
      showNotification('You have new notifications');
    }
  }
}

/**
 * Display a notification to the user
 * @param {string} message - The notification message
 */
function showNotification(message) {
  // Create notification element
  const notification = document.createElement('div');
  notification.className = 'notification';
  notification.textContent = message;

  // Add close button
  const closeBtn = document.createElement('span');
  closeBtn.className = 'notification-close';
  closeBtn.innerHTML = '&times;';
  closeBtn.addEventListener('click', function () {
    notification.remove();
  });
  notification.appendChild(closeBtn);

  // Add to the page
  document.body.appendChild(notification);

  // Auto-remove after 5 seconds
  setTimeout(() => {
    if (document.body.contains(notification)) {
      notification.remove();
    }
  }, 5000);
}

/**
 * Handle user logout
 */
function logoutUser() {
  // Clear user data
  localStorage.removeItem('userData');

  // Redirect to login page
  window.location.href = 'login.html';
}

